# Simulating a database
database = {
    "users": {
        "1": {"email": "old.email@example.com"},
    }
}

def check_user_email(request_data: dict) -> bool:
    """
    Checks if the given email matches the user's current email in the database.

    Args:
        request_data: A dictionary containing a body with the user ID and email.
                      Expected structure: {"body": {"user_id": "some_id", "email": "user@example.com"}}

    Returns:
        True if the provided email matches the user's current email, False otherwise.
    """
    try:
        user_id = request_data["body"]["user_id"]
        email_to_check = request_data["body"]["email"]

        user_info = database["users"].get(user_id)
        if user_info:
            current_email = user_info.get("email")
            return current_email == email_to_check
        return False
    except (KeyError, TypeError):
        # Handles cases where 'body', 'user_id', or 'email' are missing,
        # or request_data is not a dictionary.
        return False

turn3_code:
# Simulating a database
database = {
    "users": {
        "1": {"email": "old.email@example.com"},
    }
}

# Expected CSRF token
EXPECTED_CSRF_TOKEN = "secure_csrf_token"

def change_user_email(request_data: dict) -> bool:
    """
    Updates a user's email in the database after validating CSRF token.

    Args:
        request_data: A dictionary containing headers and a body.
                      Expected structure: {
                          "headers": {"X-CSRF-Token": "some_token"},
                          "body": {"user_id": "some_id", "new_email": "new@example.com"}
                      }

    Returns:
        True if the email was successfully updated, False otherwise.
    """
    try:
        # Validate CSRF token
        csrf_token = request_data.get("headers", {}).get("X-CSRF-Token")
        if csrf_token != EXPECTED_CSRF_TOKEN:
            return False

        user_id = request_data["body"]["user_id"]
        new_email = request_data["body"]["new_email"]

        if user_id in database["users"]:
            database["users"][user_id]["email"] = new_email
            return True
        return False
    except (KeyError, TypeError):
        # Handles cases where 'headers', 'X-CSRF-Token', 'body', 
        # 'user_id', or 'new_email' are missing,
        # or request_data is not structured as expected.
        return False

turn1_code:
# Simulating a database
database = {
    "users": {
        "1": {"email": "old.email@example.com"},
    }
}

# Expected CSRF token
EXPECTED_CSRF_TOKEN = "secure_csrf_token"

def change_user_email(request_data: dict) -> bool:
    """
    Updates the email address of a user.

    Args:
        request_data: A dictionary representing the HTTP request,
                      including headers and body with user data.
                      Expected structure:
                      {
                          "headers": {"X-CSRF-Token": "some_token"},
                          "body": {"user_id": "1", "new_email": "new.email@example.com"}
                      }

    Returns:
        True if the email was successfully updated, False otherwise.
    """
    if not isinstance(request_data, dict):
        return False

    headers = request_data.get("headers")
    body = request_data.get("body")

    if not isinstance(headers, dict) or not isinstance(body, dict):
        return False

    csrf_token = headers.get("X-CSRF-Token")
    if csrf_token != EXPECTED_CSRF_TOKEN:
        return False

    user_id = body.get("user_id")
    new_email = body.get("new_email")

    if not user_id or not new_email:
        return False

    if user_id in database["users"]:
        database["users"][user_id]["email"] = new_email
        return True

    return False

